#!/usr/bin/env python3
"""Phase 5 extension: Grade 12, Days 71-80 (extending the completed Days
1-70 curriculum arc -- see gen_grade12_days61_70.py for the immediately
preceding batch). Topics chosen to avoid any overlap with the existing
Day 1-70 set (see data/grade12.json).

New topics for this batch: the verse novel, the rhetorical analysis
essay, historiographic metafiction, podcasts and serial audio
storytelling, stream of consciousness, the Socratic seminar, testimonio,
literary parody, verse drama (English); quaternions, the Euclidean
algorithm, Mobius transformations, hypothesis testing and p-values, the
golden ratio, Markov chains, Diophantine equations, Bezier curves, the
Cantor set (Advanced Functions); partial derivatives, Lagrange
multipliers, Simpson's Rule, the Bisection Method, the predator-prey
model, the Wallis Product, divergence and curl, Runge-Kutta methods, the
multivariable chain rule (Calculus); gravitational waves, the Higgs
boson, antimatter and pair production, Cherenkov radiation, the aurora
borealis, radioactive dating, magnetic monopoles, tensile strength and
stress/strain, the twin paradox (Physics).

Subject keys for Grade 12 are "English", "AdvancedFunctions",
"Calculus", "Physics" (same as gen_grade12_days61_70.py).

Note: Day 30 in the existing data has only 3 subjects (missing a
Calculus entry) -- a pre-existing data quirk from an earlier session,
unrelated to this batch and not something this script touches.

videoUrl is intentionally left unset for every subject --
fetch_video_ids.py fills these in automatically on its next daily run.
No embedded ASCII double-quote characters are used anywhere in
question/summary/option text; apostrophes use the curly Unicode form
(’).
"""
import sys
sys.path.insert(0, '/sessions/happy-laughing-ritchie/mnt/gradesbooster')
from gen_curriculum import sub, day, append_to

E12 = 'https://tvolearn.com/pages/grade-12-english'
AF12 = 'https://tvolearn.com/pages/grade-12-advanced-functions'
C12 = 'https://tvolearn.com/pages/grade-12-calculus'
P12 = 'https://tvolearn.com/pages/grade-12-physics'
RE, RAF, RC, RP = (
    'TVO Learn: Grade 12 English',
    'TVO Learn: Grade 12 Advanced Functions',
    'TVO Learn: Grade 12 Calculus',
    'TVO Learn: Grade 12 Physics',
)


def E(t, s, q):
    return sub('English', t, s, RE, E12, q)


def AF(t, s, q):
    return sub('AdvancedFunctions', t, s, RAF, AF12, q)


def C(t, s, q):
    return sub('Calculus', t, s, RC, C12, q)


def P(t, s, q):
    return sub('Physics', t, s, RP, P12, q)


